SELECT MAX(oMonetaryAmount.hasamount) AS AggResult1 FROM fiben.listedsecurity AS oListedSecurity INNER JOIN fiben.monetaryamount AS oMonetaryAmount ON oListedSecurity.haslasttradedvalue = oMonetaryAmount.monetaryamountid WHERE oMonetaryAmount.hasamount u003c 100 AND oMonetaryAmount.hasamount u003c 100.0 ORDER BY CASE WHEN MAX(oMonetaryAmount.hasamount) IS NULL THEN 1 ELSE 0 END DESC, MAX(oMonetaryAmount.hasamount) DESC OFFSET 0 ROWS FETCH FIRST 1 ROWS ONLY